import React, { useState } from 'react';

const PropietariosYTipoSocietario = () => {
  const [tieneTipoSocietario, setTieneTipoSocietario] = useState(true);
  const [tipoSeleccionado, setTipoSeleccionado] = useState('SRL');

  const propietarios = [
    { nombre: 'Juan Pérez', inicio: '2010', fin: '2015' },
    { nombre: 'Ana Gómez', inicio: '2015', fin: '2020' },
    { nombre: 'Carlos Quispe', inicio: '2020', fin: '2022' },
    { nombre: 'Lucía Rodríguez', inicio: '2022', fin: 'Presente' },
  ];

  const tiposSocietarios = [
    'SRL',
    'SA',
    'SC',
    'SE',
    'Empresa Unipersonal',
    'Cooperativa',
    'Asociación Civil',
    'ONG',
    'Fundación'
  ];

  return (
    <div className="min-h-screen bg-[#f2f0df] flex justify-center items-start pt-28 px-6 pb-6">
      <div className="bg-white shadow-xl rounded-xl p-6 w-full max-w-3xl space-y-6">
        <h2 className="text-2xl font-bold text-[#9fa56c] text-center">Propietarios y Tipo Societario</h2>

        {/* Lista de Propietarios */}
        <div>
          <label className="block text-gray-700 font-semibold mb-2">Propietarios:</label>
          <div className="space-y-2">
            {propietarios.map((prop, index) => (
              <div key={index} className="flex justify-between bg-[#e1e4c5] p-2 rounded-md">
                <span className="font-medium text-sm text-[#202020]">{prop.nombre}</span>
                <span className="text-sm">{prop.inicio} - {prop.fin}</span>
              </div>
            ))}
          </div>
          <div className="flex gap-3 mt-3">
            <button className="px-3 py-1 bg-[#9fa56c] text-white rounded-full text-sm hover:bg-[#8a944e]">+</button>
            <button className="px-3 py-1 bg-[#9fa56c] text-white rounded-full text-sm hover:bg-[#8a944e]">−</button>
          </div>
        </div>

        {/* Tipo Societario */}
        <div>
          <label className="block text-gray-700 font-semibold mb-2">Tipo Societario:</label>
          <div className="flex items-center gap-4">
            <label className="flex items-center gap-2">
              <input
                type="checkbox"
                checked={tieneTipoSocietario}
                onChange={() => setTieneTipoSocietario(!tieneTipoSocietario)}
                className="form-checkbox h-4 w-4 text-[#9fa56c] border-gray-300"
              />
              <span className="text-sm text-gray-800">Tiene tipo societario</span>
            </label>

            {tieneTipoSocietario && (
              <select
                value={tipoSeleccionado}
                onChange={(e) => setTipoSeleccionado(e.target.value)}
                className="p-2 border border-gray-300 rounded-md text-sm"
              >
                {tiposSocietarios.map((tipo, index) => (
                  <option key={index} value={tipo}>{tipo}</option>
                ))}
              </select>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default PropietariosYTipoSocietario;
